// Utility function: get display name from category slug
function getCategoryName(categorySlug) {
    if (siteConfig.categoryData && siteConfig.categoryData.length > 0) {
        for (const cat of siteConfig.categoryData) {
            if (cat.category_slug === categorySlug || cat.slug === categorySlug) {
                return cat.category_name || cat.name || categorySlug;
            }
        }
    }
    return categorySlug.charAt(0).toUpperCase() + categorySlug.slice(1);
}

class DataService {
    constructor() {
        this.articleIndex = {
            articles: siteConfig.articles,
            categories: siteConfig.categories
        };
        this.categoryIndex = {};
        this.articleCache = {};
        
        // Initialize category index
        siteConfig.categories.forEach(cat => {
            this.categoryIndex[cat] = siteConfig.articles.filter(a => a.category === cat);
        });
    }

    async loadArticleIndex() {
        return this.articleIndex;
    }

    async loadCategoryIndex() {
        return this.categoryIndex;
    }

    async loadArticleById(id) {
        if (this.articleCache[id]) {
            return this.articleCache[id];
        }
        try {
            // Basic data is embedded, but full content may still need loading
            // For simplicity, we assume articles have full content or try fetch
            const article = siteConfig.articles.find(a => a.id === id);
            if (article && article.content) {
                return article;
            }
            
            const response = await fetch(`data/article-${id}.json`);
            if (!response.ok) throw new Error(`Failed to load article ${id}`);
            const fullArticle = await response.json();
            this.articleCache[id] = fullArticle;
            return fullArticle;
        } catch (error) {
            console.error('Error loading article:', error);
            return null;
        }
    }

    async loadArticleBySlug(slug) {
        const article = siteConfig.articles.find(a => a.slug === slug);
        if (article) {
            return await this.loadArticleById(article.id);
        }
        return null;
    }

    async getArticlesByCategory(category) {
        return this.categoryIndex[category] || [];
    }
}

class App {
    constructor() {
        this.dataService = new DataService();
        this.itemsPerPage = 15;
        this.currentPage = 1;
        this.init();
    }

    init() {
        window.addEventListener('hashchange', () => this.handleRoute());
        this.handleRoute();
        // Load sidebar content
        this.renderSidebarCategories();
        this.loadRecommendedNews();
        this.loadCategorySpecificWidgets();
        // Update footer links
        this.updateFooterLinks();
        // Initialize ad features
        this.initFloatingAds();
        // Initialize mobile menu
        this.initMobileMenu();
    }
    
    initMobileMenu() {
        const toggle = document.getElementById('mobile-menu-toggle');
        const nav = document.getElementById('main-nav');
        if (toggle && nav) {
            toggle.onclick = (e) => {
                e.stopPropagation();
                nav.classList.toggle('active');
                toggle.classList.toggle('active');
            };
            
            // Close menu when clicking outside
            document.addEventListener('click', (e) => {
                if (!toggle.contains(e.target) && !nav.contains(e.target)) {
                    nav.classList.remove('active');
                    toggle.classList.remove('active');
                }
            });
            
            // Close menu when clicking a link
            nav.querySelectorAll('a').forEach(link => {
                link.onclick = () => {
                    nav.classList.remove('active');
                    toggle.classList.remove('active');
                };
            });
        }
    }
    
    initFloatingAds() {
        const floatingAds = document.querySelectorAll('.floating-ad');
        floatingAds.forEach(ad => {
            // Add close button
            const closeBtn = document.createElement('div');
            closeBtn.className = 'close-ad-btn';
            closeBtn.innerHTML = '×';
            closeBtn.onclick = (e) => {
                e.stopPropagation();
                ad.style.display = 'none';
            };
            ad.appendChild(closeBtn);
            
            // Add countdown timer
            const countdownEl = document.createElement('div');
            countdownEl.className = 'ad-countdown';
            ad.appendChild(countdownEl);
            
            let timeLeft = 15;
            const updateCountdown = () => {
                countdownEl.innerHTML = `Auto-close in ${timeLeft}s`;
                if (timeLeft <= 0) {
                    ad.style.opacity = '0';
                    setTimeout(() => ad.style.display = 'none', 500);
                    clearInterval(timer);
                }
                timeLeft -= 1;
            };
            
            updateCountdown();
            const timer = setInterval(updateCountdown, 1000);
        });
    }

    async loadCategorySpecificWidgets() {
        const articleIndex = await this.dataService.loadArticleIndex();
        if (!articleIndex || !siteConfig.categories) return;
        
        const container = document.getElementById('sidebar-category-widgets');
        if (!container) return;

        // Pick 2 random categories
        const shuffledCats = [...siteConfig.categories].sort(() => Math.random() - 0.5);
        const selectedCats = shuffledCats.slice(0, 2);
        
        let html = '';
        for (const cat of selectedCats) {
            const catArticles = articleIndex.articles
                .filter(a => a.category === cat)
                .sort(() => Math.random() - 0.5)
                .slice(0, 3);
            
            if (catArticles.length > 0) {
                html += `
                    <div class="sidebar-widget">
                        <h3>Trending in ${getCategoryName(cat)}</h3>
                        <div class="sidebar-news-list">
                            ${catArticles.map(a => `
                                <div class="sidebar-news-item">
                                    <a href="#/article/${a.slug}">${a.title}</a>
                                </div>
                            `).join('')}
                        </div>
                    </div>
                `;
            }
        }
        container.innerHTML = html;
    }
    
    renderSidebarCategories() {
        const container = document.getElementById('sidebar-categories');
        if (!container || !siteConfig.categories) return;
        
        let html = '<ul style="list-style: none; padding: 0;">';
        for (const cat of siteConfig.categories) {
            html += `
                <li style="margin-bottom: 0.5rem; border-bottom: 1px solid #f0f0f0; padding-bottom: 0.5rem;">
                    <a href="#/category/${cat}" style="text-decoration: none; color: ${siteConfig.design.color_scheme.text}; display: block;">
                        ${getCategoryName(cat)}
                    </a>
                </li>
            `;
        }
        html += '</ul>';
        container.innerHTML = html;
    }
    
    updateFooterLinks() {
        const container = document.getElementById('footer-links-container');
        if (!container) return;
        
        const links = [
            { href: 'about.html', text: 'About Us' },
            { href: 'contact.html', text: 'Contact Us' },
            { href: 'privacy.html', text: 'Privacy Policy' },
            { href: 'terms.html', text: 'Terms of Service' },
            { href: 'cookie-policy.html', text: 'Cookie Policy' },
            { href: 'ad-policy.html', text: 'Ad Policy' },
            { href: 'dmca.html', text: 'DMCA' },
            { href: 'disclaimer.html', text: 'Disclaimer' },
            { href: 'accessibility.html', text: 'Accessibility' },
            { href: 'faq.html', text: 'FAQ' },
            { href: 'feedback.html', text: 'Feedback' },
            { href: 'data-request.html', text: 'Data Request' },
            { href: 'do-not-sell.html', text: 'Do Not Sell My Info' },
            { href: 'refund-policy.html', text: 'Refund Policy' }
        ];
        
        container.innerHTML = links.map(link => `<a href="${link.href}">${link.text}</a>`).join('');
    }

    async loadRecommendedNews() {
        const articleIndex = await this.dataService.loadArticleIndex();
        if (!articleIndex) return;
        
        // Select 5 random articles as recommended news
        const shuffled = [...articleIndex.articles].sort(() => Math.random() - 0.5);
        const recommended = shuffled.slice(0, 5);
        
        // Render to sidebar
        this.renderRecommendedNews(recommended);
    }
    
    renderRecommendedNews(newsList) {
        const container = document.getElementById('sidebar-recommended-news');
        if (!container) return;
        
        let html = '';
        for (const news of newsList) {
            html += `
                <div class="sidebar-news-item">
                    <a href="#/article/${news.slug}">${news.title}</a>
                </div>
            `;
        }
        
        container.innerHTML = html;
    }

    handleRoute() {
        let hash = window.location.hash.slice(1) || '/';
        if (hash.startsWith('/')) {
            hash = hash.slice(1);
        }
        const parts = hash.split('/');
        const route = parts[0];

        if (route === '' || route === 'page') {
            this.currentPage = route === 'page' ? parseInt(parts[1]) || 1 : 1;
            this.renderHome();
        } else if (route === 'category' && parts[1]) {
            this.currentPage = parts[2] ? parseInt(parts[2]) || 1 : 1;
            this.renderCategory(parts[1]);
        } else if (route === 'article' && parts[1]) {
            this.renderArticle(parts[1]);
        } else {
            this.currentPage = 1;
            this.renderHome();
        }
        
        // Scroll to top on every route change
        window.scrollTo(0, 0);
    }

    showLoading() {
        const app = document.getElementById('app');
        app.innerHTML = '<div class="loading">Loading...</div>';
    }

    async renderHome() {
        this.showLoading();
        const app = document.getElementById('app');
        const bannerContainer = document.getElementById('home-banner-container');
        const articleIndex = await this.dataService.loadArticleIndex();
        
        if (!articleIndex) {
            app.innerHTML = '<h1>Failed to load content</h1>';
            return;
        }

        // Render home banner
        if (bannerContainer) {
            bannerContainer.innerHTML = `
                <div class="home-banner">
                    <div class="container">
                        <h2>Welcome to ${siteConfig.design.site_title}</h2>
                        <p>Explore latest articles and get quality content</p>
                    </div>
                </div>`;
            bannerContainer.style.display = 'block';
        }

        let html = '';
        html += '<h1 class="page-title">All Articles</h1>';
        
        // Pagination logic
        const totalItems = articleIndex.articles.length;
        const totalPages = Math.ceil(totalItems / this.itemsPerPage);
        const startIndex = (this.currentPage - 1) * this.itemsPerPage;
        const endIndex = startIndex + this.itemsPerPage;
        const currentArticles = articleIndex.articles.slice(startIndex, endIndex);
        
        html += '<div class="article-grid">';
        
        for (let i = 0; i < currentArticles.length; i++) {
            const articleMeta = currentArticles[i];
            html += this.renderArticleCardSimple(articleMeta);
            
            // Insert AD-07 in-feed ad every 6 articles
            if ((i + 1) % 6 === 0) {
                html += this.renderAdSlot('AD-07', 'Sponsored Content');
            }
        }
        
        html += '</div>';

        // Add pagination controls
        if (totalPages > 1) {
            html += this.renderPaginationControls(totalPages, '#/page/');
        }
        
        app.innerHTML = html;
        
        // After rendering, lazy load ads with delay
        setTimeout(() => {
            if (window.AdInjector) {
                window.AdInjector.scanAndLoadAllAds();
            }
        }, 100);
    }

    async renderCategory(category) {
        this.showLoading();
        const app = document.getElementById('app');
        const bannerContainer = document.getElementById('home-banner-container');
        
        // Hide home banner on category page
        if (bannerContainer) {
            bannerContainer.innerHTML = '';
            bannerContainer.style.display = 'none';
        }

        const categoryArticles = await this.dataService.getArticlesByCategory(category);
        
        if (!categoryArticles) {
            app.innerHTML = '<h1>Failed to load content</h1>';
            return;
        }

        // Pagination logic
        const totalItems = categoryArticles.length;
        const totalPages = Math.ceil(totalItems / this.itemsPerPage);
        const startIndex = (this.currentPage - 1) * this.itemsPerPage;
        const endIndex = startIndex + this.itemsPerPage;
        const currentArticles = categoryArticles.slice(startIndex, endIndex);

        let html = `<h1 class="page-title">${getCategoryName(category)}</h1>`;
        html += '<div class="article-grid">';
        
        for (let i = 0; i < currentArticles.length; i++) {
            const articleMeta = currentArticles[i];
            html += this.renderArticleCardSimple(articleMeta);
            
            // Insert AD-07 in-feed ad every 6 articles
            if ((i + 1) % 6 === 0) {
                html += this.renderAdSlot('AD-07', 'Sponsored Content');
            }
        }
        
        html += '</div>';

        // Add pagination controls
        if (totalPages > 1) {
            html += this.renderPaginationControls(totalPages, `#/category/${category}/`);
        }
        
        app.innerHTML = html;
        
        // After rendering, lazy load ads with delay
        setTimeout(() => {
            if (window.AdInjector) {
                window.AdInjector.scanAndLoadAllAds();
            }
        }, 100);
    }

    renderPaginationControls(totalPages, baseUrl) {
        let html = '<div class="pagination">';
        
        if (this.currentPage > 1) {
            html += `<a href="${baseUrl}${this.currentPage - 1}" class="page-btn">Previous</a>`;
        }
        
        for (let i = 1; i <= totalPages; i++) {
            const isActive = i === this.currentPage;
            // Display max 10 page buttons to prevent overflow
            if (i === 1 || i === totalPages || (i >= this.currentPage - 2 && i <= this.currentPage + 2)) {
                html += `<a href="${baseUrl}${i}" class="page-btn ${isActive ? 'active' : ''}">${i}</a>`;
            } else if (i === this.currentPage - 3 || i === this.currentPage + 3) {
                html += `<span>...</span>`;
            }
        }
        
        if (this.currentPage < totalPages) {
            html += `<a href="${baseUrl}${this.currentPage + 1}" class="page-btn">Next</a>`;
        }
        
        html += '</div>';
        return html;
    }

    async renderArticle(slug) {
        this.showLoading();
        const app = document.getElementById('app');
        const bannerContainer = document.getElementById('home-banner-container');
        
        // Hide home banner on article page
        if (bannerContainer) {
            bannerContainer.innerHTML = '';
            bannerContainer.style.display = 'none';
        }

        const article = await this.dataService.loadArticleBySlug(slug);
        
        if (!article) {
            app.innerHTML = '<h1>Article not found</h1>';
            return;
        }
        
        // Render article with ads
        app.innerHTML = this.renderArticleWithAds(article);
        
        // Update page title
        document.title = article.title + ' - ' + siteConfig.siteId;
        if (article.seo && article.seo.title_tag) {
            document.title = article.seo.title_tag;
        }
        
        // After rendering, lazy load ads with delay
        setTimeout(() => {
            if (window.AdInjector) {
                window.AdInjector.scanAndLoadAllAds();
            }
        }, 100);
    }

    renderArticleWithAds(article) {
        let html = '<div class="article-full">';
        
        html += '<div style="margin-bottom: 1rem;">';
        html += `<a href="#/">Home</a> | `;
        html += `<a href="#/category/${article.category}">${getCategoryName(article.category)}</a>`;
        html += '</div>';
        
        html += `<span class="category-tag">${getCategoryName(article.category)}</span>`;
        html += `<h1>${article.title}</h1>`;
        html += `<p class="article-meta">${new Date(article.created_at).toLocaleDateString()}`;
        
        if (article.geo) {
            html += ` | Location: ${article.geo.city}, ${article.geo.country}`;
        }
        html += `</p>`;
        
        // Add article image
        if (article.image && article.image.url) {
            html += `<img src="${article.image.url}" alt="${article.image.alt || article.title}" style="width: 100%; max-height: 400px; object-fit: cover; margin: 1rem 0; border-radius: 8px;">`;
        }
        
        // Split article content and insert ads
        const paragraphs = article.content.split('</p>').filter(p => p.trim());
        
        // Insert AD-04 after first paragraph
        if (paragraphs.length > 0) {
            html += paragraphs[0] + '</p>';
            html += this.renderAdSlot('AD-04', 'In-Article 1');
        }
        
        // Insert AD-05 at 50% position
        const middleIndex = Math.floor(paragraphs.length / 2);
        for (let i = 1; i < paragraphs.length; i++) {
            html += paragraphs[i] + '</p>';
            
            if (i === middleIndex && middleIndex > 0) {
                html += this.renderAdSlot('AD-05', 'In-Article 2');
            }
        }
        
        // Insert AD-06 at end of article
        html += this.renderAdSlot('AD-06', 'In-Article 3');
        
        html += '</div>';
        return html;
    }

    renderAdSlot(slotId, label) {
        return `
            <div class="ad-slot" 
                 data-ad-container="true" 
                 data-ad-id="${slotId}" 
                 data-ad-position="${slotId.toLowerCase()}"
                 data-ad-networks="adsense,adsterra,gam"
                 data-ad-status="pending"
                 style="margin: 2rem 0; min-height: 200px; display: none;">
                <div class="ad-skeleton">
                    <div class="ad-label">${slotId} - ${label}</div>
                </div>
                <div class="ad-content" data-ad-network="adsense"></div>
                <div class="ad-content" data-ad-network="adsterra"></div>
                <div class="ad-content" data-ad-network="gam"></div>
            </div>
        `;
    }

    renderArticleCardSimple(articleMeta) {
        // Make entire card clickable
        let html = `<div class="article-card" style="cursor: pointer;" onclick="window.location.hash='/article/${articleMeta.slug}'">`;
        
        // Add article image
        if (articleMeta.image && articleMeta.image.url) {
            html += `<div class="article-card-image" style="width: 100%; height: 150px; overflow: hidden; border-radius: 4px; margin-bottom: 0.5rem;">`;
            html += `<img src="${articleMeta.image.url}" alt="${articleMeta.image.alt || articleMeta.title}" style="width: 100%; height: 100%; object-fit: cover;">`;
            html += '</div>';
        }
        
        html += '<div class="article-card-content">';
        html += `<span class="category-tag">${getCategoryName(articleMeta.category)}</span>`;
        html += `<h3><a href="#/article/${articleMeta.slug}">${articleMeta.title}</a></h3>`;
        html += `<p>Read more about ${articleMeta.title}...</p>`;
        html += '</div></div>';
        
        return html;
    }
}

document.addEventListener('DOMContentLoaded', () => {
    new App();
});